      const issueTx = await contract.issueCropNFT(cropName, amount, value, ipfsHash, {
        value: mintPrice,
      });
      await issueTx.wait();
      alert('Crop NFT issued successfully!');
    } catch (err) {
      console.error('Error occurred: ', err);
      alert('Error occurred. Check the console for more details.');
