          </Col>
        </Row>
        <Row>
          <Col>
            <Form.Group controlId="value">
              <Form.Label>Value</Form.Label>
              <Form.Control type="number" placeholder="Enter value" value={value} onChange={(e) => setValue(e.target.value)} />
            </Form.Group>
          </Col>
          <Col>
            <Form.Group controlId="ipfsHash">
              <Form.Label>IPFS Hash</Form.Label>
